import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Outlet, NavLink } from 'react-router-dom';
import { LayoutDashboard, FileText, ClipboardList, Users, Box, Bath, Calendar, Calculator, BarChart3, Settings, Menu, X, Globe } from 'lucide-react';

const menuItems = [
  { path: '/', label: 'Dashboard', icon: LayoutDashboard, end: true },
  { path: '/presupuestos', label: 'PRESUPUESTOS LOCAL', icon: FileText },
  { path: '/presupuestos-online', label: 'PRESUPUESTOS EN LÍNEA', icon: Globe },
  { path: '/ordenes', label: 'Órdenes de Trabajo', icon: ClipboardList },
  { path: '/clientes', label: 'Clientes', icon: Users },
  { path: '/materiales', label: 'Materiales', icon: Box },
  { path: '/stock-piletas', label: 'Stock de Piletas', icon: Bath },
  { path: '/mediciones', label: 'Mediciones', icon: Calendar },
  { path: '/calculadora', label: 'Calculadora', icon: Calculator },
  { path: '/reportes', label: 'Reportes', icon: BarChart3 },
  { path: '/configuracion', label: 'Configuración', icon: Settings },
];

export default function Layout() {
  const [isOpen, setIsOpen] = useState(false);
  const [isPinned, setIsPinned] = useState(() => localStorage.getItem('sidebarPinned') === 'true');
  const [mobileOpen, setMobileOpen] = useState(false);
  const leaveTimer = useRef(null);
  const sidebarRef = useRef(null);

  useEffect(() => {
    localStorage.setItem('sidebarPinned', isPinned);
  }, [isPinned]);

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (isPinned) return;
      if (e.clientX <= 15) {
        if (leaveTimer.current) {
          clearTimeout(leaveTimer.current);
          leaveTimer.current = null;
        }
        setIsOpen(true);
      }
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, [isPinned]);

  const handleMouseLeave = useCallback(() => {
    if (isPinned) return;
    if (leaveTimer.current) clearTimeout(leaveTimer.current);
    leaveTimer.current = setTimeout(() => {
      setIsOpen(false);
    }, 500);
  }, [isPinned]);

  const handleMouseEnter = useCallback(() => {
    if (isPinned) return;
    if (leaveTimer.current) {
      clearTimeout(leaveTimer.current);
      leaveTimer.current = null;
    }
    setIsOpen(true);
  }, [isPinned]);

  const togglePin = () => setIsPinned((p) => !p);

  const sidebarVisible = isPinned || isOpen || mobileOpen;

  return (
    <div>
      {/* 8px trigger edge */}
      <div
        className={`sidebar-trigger${isPinned ? ' hidden' : ''}`}
        onMouseEnter={handleMouseEnter}
      />

      {/* Mobile hamburger */}
      <button
        className="btn btn-outline mobile-hamburger"
        onClick={() => setMobileOpen(!mobileOpen)}
        style={{ position: 'fixed', top: 12, left: 12, zIndex: 1100, display: 'none' }}
      >
        {mobileOpen ? <X size={18} /> : <Menu size={18} />}
      </button>

      <aside
        ref={sidebarRef}
        className={`sidebar${sidebarVisible ? ' visible' : ''}${isPinned ? ' pinned' : ''}`}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        {/* Pin button */}
        <button
          onClick={togglePin}
          title={isPinned ? 'Desfijar menú' : 'Fijar menú'}
          style={{
            position: 'absolute',
            top: 12,
            right: 12,
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            fontSize: 16,
            opacity: 0.6,
            transition: 'opacity 0.2s',
            color: '#94a3b8',
          }}
          onMouseEnter={(e) => e.currentTarget.style.opacity = '1'}
          onMouseLeave={(e) => e.currentTarget.style.opacity = '0.6'}
        >
          {isPinned ? '📌' : '📍'}
        </button>

        <div style={{ padding: '20px 24px', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
          <h1 style={{ color: 'white', fontSize: 20, fontWeight: 800, letterSpacing: '-0.5px' }}>
            AFAMAR
          </h1>
          <p style={{ color: '#94a3b8', fontSize: 12, marginTop: 2 }}>
            Mármoles & Granitos
          </p>
        </div>
        <nav style={{ padding: '12px' }}>
          {menuItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              end={item.end}
              onClick={() => { setMobileOpen(false); if (!isPinned) setIsOpen(false); }}
              style={({ isActive }) => ({
                display: 'flex',
                alignItems: 'center',
                gap: 10,
                padding: '10px 14px',
                borderRadius: 8,
                textDecoration: 'none',
                fontSize: 14,
                fontWeight: 500,
                marginBottom: 2,
                color: isActive ? 'white' : '#94a3b8',
                background: isActive ? 'rgba(59,130,246,0.15)' : 'transparent',
                transition: 'all 0.2s',
              })}
            >
              <item.icon size={18} />
              {item.label}
            </NavLink>
          ))}
        </nav>
      </aside>

      {/* Mobile overlay */}
      {mobileOpen && (
        <div
          onClick={() => setMobileOpen(false)}
          style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 999 }}
        />
      )}

      <div className="main-content">
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 24 }}>
          <div />
          <div style={{ fontSize: 14, color: '#64748b' }}>
            {new Date().toLocaleDateString('es-AR', {
              weekday: 'long',
              year: 'numeric',
              month: 'long',
              day: 'numeric',
            })}
          </div>
        </div>
        <Outlet />
      </div>

      <style>{`
        @media (max-width: 1024px) {
          .mobile-hamburger { display: inline-flex !important; }
          .sidebar-trigger { display: none !important; }
          .main-content { padding-top: 56px; }
        }
      `}</style>
    </div>
  );
}
